def solution(limit=100):
    max_sum = 0
    for a in range(limit):
        for b in range(limit):
            # Correctly calculate a to the power of b
            res = a**b
            # Sum the digits of the result
            digit_sum = sum(int(d) for d in str(res))
            if digit_sum > max_sum:
                max_sum = digit_sum
    return max_sum


if __name__ == "__main__":
    print(solution(100))
